import React, { useState } from 'react';
import { useStore } from '../../store';
import { USERS } from '../../data/generator';
import { Status, Priority } from '../../types';
import { useHasActiveFilters } from '../../hooks/useURLSync';

const STATUSES: { value: Status; label: string }[] = [
  { value: 'todo', label: 'To Do' },
  { value: 'in-progress', label: 'In Progress' },
  { value: 'in-review', label: 'In Review' },
  { value: 'done', label: 'Done' },
];

const PRIORITIES: { value: Priority; label: string }[] = [
  { value: 'critical', label: '🔴 Critical' },
  { value: 'high', label: '🟠 High' },
  { value: 'medium', label: '🟡 Medium' },
  { value: 'low', label: '🟢 Low' },
];

type OpenDropdown = 'status' | 'priority' | 'assignee' | null;

export default function FilterBar() {
  const { filters, setFilters, clearFilters } = useStore((s) => ({
    filters: s.filters,
    setFilters: s.setFilters,
    clearFilters: s.clearFilters,
  }));
  const hasActive = useHasActiveFilters();
  const [open, setOpen] = useState<OpenDropdown>(null);

  const toggle = (dropdown: OpenDropdown) => setOpen(open === dropdown ? null : dropdown);

  const toggleStatus = (v: Status) => {
    const cur = filters.status;
    setFilters({ status: cur.includes(v) ? cur.filter((s) => s !== v) : [...cur, v] });
  };

  const togglePriority = (v: Priority) => {
    const cur = filters.priority;
    setFilters({ priority: cur.includes(v) ? cur.filter((p) => p !== v) : [...cur, v] });
  };

  const toggleAssignee = (id: string) => {
    const cur = filters.assigneeIds;
    setFilters({ assigneeIds: cur.includes(id) ? cur.filter((a) => a !== id) : [...cur, id] });
  };

  // Close on outside click
  const onBlur = () => setTimeout(() => setOpen(null), 150);

  return (
    <div className="filter-bar">
      <div className="filter-group">
        {/* Status */}
        <div className="filter-dropdown-wrap" onBlur={onBlur}>
          <button
            className={`filter-btn ${filters.status.length ? 'active' : ''}`}
            onClick={() => toggle('status')}
          >
            Status {filters.status.length ? `(${filters.status.length})` : ''} ▾
          </button>
          {open === 'status' && (
            <div className="filter-menu">
              {STATUSES.map((s) => (
                <label key={s.value} className="filter-option">
                  <input
                    type="checkbox"
                    checked={filters.status.includes(s.value)}
                    onChange={() => toggleStatus(s.value)}
                  />
                  {s.label}
                </label>
              ))}
            </div>
          )}
        </div>

        {/* Priority */}
        <div className="filter-dropdown-wrap" onBlur={onBlur}>
          <button
            className={`filter-btn ${filters.priority.length ? 'active' : ''}`}
            onClick={() => toggle('priority')}
          >
            Priority {filters.priority.length ? `(${filters.priority.length})` : ''} ▾
          </button>
          {open === 'priority' && (
            <div className="filter-menu">
              {PRIORITIES.map((p) => (
                <label key={p.value} className="filter-option">
                  <input
                    type="checkbox"
                    checked={filters.priority.includes(p.value)}
                    onChange={() => togglePriority(p.value)}
                  />
                  {p.label}
                </label>
              ))}
            </div>
          )}
        </div>

        {/* Assignee */}
        <div className="filter-dropdown-wrap" onBlur={onBlur}>
          <button
            className={`filter-btn ${filters.assigneeIds.length ? 'active' : ''}`}
            onClick={() => toggle('assignee')}
          >
            Assignee {filters.assigneeIds.length ? `(${filters.assigneeIds.length})` : ''} ▾
          </button>
          {open === 'assignee' && (
            <div className="filter-menu">
              {USERS.map((u) => (
                <label key={u.id} className="filter-option">
                  <input
                    type="checkbox"
                    checked={filters.assigneeIds.includes(u.id)}
                    onChange={() => toggleAssignee(u.id)}
                  />
                  <div className="assignee-dot" style={{ background: u.color }}>{u.initials}</div>
                  {u.name}
                </label>
              ))}
            </div>
          )}
        </div>

        {/* Date range */}
        <div className="date-range-group">
          <input
            type="date"
            className="date-input"
            value={filters.dueDateFrom}
            onChange={(e) => setFilters({ dueDateFrom: e.target.value })}
            placeholder="From"
          />
          <span className="date-sep">→</span>
          <input
            type="date"
            className="date-input"
            value={filters.dueDateTo}
            onChange={(e) => setFilters({ dueDateTo: e.target.value })}
            placeholder="To"
          />
        </div>
      </div>

      {hasActive && (
        <button className="clear-btn" onClick={clearFilters}>
          ✕ Clear all
        </button>
      )}
    </div>
  );
}
